local ngx = require("ngx")
local jwt = require("resty.jwt")

-- Validate the JWT token and extract the user's role
local token = ngx.var.http_authorization or ""
local claims, err = jwt:verify(token)
if not claims then
  ngx.log(ngx.ERR, "failed to verify JWT token: ", err)
  return ngx.exit(401)
end

-- Check if the user has the required role for this endpoint
local uri = ngx.var.uri
if not (uri:find("/admin") or uri:find("/api")) then
  -- Skip permission checks for certain endpoints
