end

local roles = { "user", "admin" }
local has_required_role = false
for _, role in ipairs(roles) do
  if claims.role == role then
    has_required_role = true
    break
  end
end

if not has_required_role then
  ngx.log(ngx.ERR, "user does not have required role for this endpoint")
  return ngx.exit(403)
end